# frozen_string_literal: true

require 'json'

module RubyLLM
  # Represents a conversation with an AI model
  class Chat
    include Enumerable

    attr_reader :model, :messages, :tools, :tool_prefs, :params, :headers, :schema, :concurrency

    def initialize(model: nil, provider: nil, assume_model_exists: false, context: nil)
      if assume_model_exists && !provider
        raise ArgumentError, 'Provider must be specified if assume_model_exists is true'
      end

      @context = context
      @config = context&.config || RubyLLM.config
      model_id = model || @config.default_model
      with_model(model_id, provider: provider, assume_exists: assume_model_exists)
      @temperature = nil
      @messages = []
      @tools = {}
      @tool_prefs = { choice: nil, calls: nil }
      @concurrency = normalize_tool_concurrency(@config.tool_concurrency)
      @params = {}
      @headers = {}
      @schema = nil
      @thinking = nil
      @citations = false
      @protocol = nil
      @on = {
        new_message: nil,
        end_message: nil,
        tool_call: nil,
        tool_result: nil
      }
      @callbacks = Hash.new { |callbacks, name| callbacks[name] = [] }
    end

    def ask(message = nil, with: nil, &)
      add_message role: :user, content: build_content(message, with)
      complete(&)
    end

    alias say ask

    def with_instructions(instructions, append: false, replace: nil)
      unless replace.nil?
        RubyLLM.deprecator.warn(
          '`replace:` is deprecated and will be removed in RubyLLM 2.0. ' \
          '`with_instructions` replaces by default; use `append: true` to append.'
        )
        append ||= replace == false
      end

      if append
        append_system_instruction(instructions)
      else
        replace_system_instruction(instructions)
      end

      self
    end

    def with_tool(tool, choice: nil, calls: nil, concurrency: @concurrency)
      unless tool.nil?
        tool_instance = tool.is_a?(Class) ? tool.new : tool
        @tools[tool_instance.name.to_sym] = tool_instance
      end
      update_tool_options(choice:, calls:)
      update_tool_concurrency(concurrency)
      self
    end

    def with_tools(*tools, replace: false, choice: nil, calls: nil, concurrency: @concurrency)
      @tools.clear if replace
      tools.compact.each { |tool| with_tool tool }
      update_tool_options(choice:, calls:)
      update_tool_concurrency(concurrency)
      self
    end

    def with_model(model_id, provider: nil, assume_exists: false)
      @model, @provider = Models.resolve(model_id, provider:, assume_exists:, config: @config)
      @connection = @provider.connection
      self
    end

    def with_temperature(temperature)
      @temperature = temperature
      self
    end

    def with_thinking(effort: nil, budget: nil)
      raise ArgumentError, 'with_thinking requires :effort or :budget' if effort.nil? && budget.nil?

      @thinking = Thinking::Config.new(effort: effort, budget: budget)
      self
    end

    def with_citations(enabled = true) # rubocop:disable Style/OptionalBooleanParameter
      @citations = enabled
      self
    end

    def with_context(context)
      @context = context
      @config = context.config
      with_model(@model.id, provider: @provider.slug, assume_exists: true)
      self
    end

    def with_params(**params)
      @params = params
      self
    end

    def with_protocol(protocol)
      @protocol = protocol
      self
    end

    def with_headers(**headers)
      @headers = headers
      self
    end

    def with_schema(schema)
      schema_instance = schema.is_a?(Class) ? schema.new : schema

      @schema = normalize_schema_payload(
        schema_instance.respond_to?(:to_json_schema) ? schema_instance.to_json_schema : schema_instance
      )

      self
    end

    def on_new_message(&)
      set_legacy_callback(:new_message, :on_new_message, :before_message, &)
    end

    def on_end_message(&)
      set_legacy_callback(:end_message, :on_end_message, :after_message, &)
    end

    def on_tool_call(&)
      set_legacy_callback(:tool_call, :on_tool_call, :before_tool_call, &)
    end

    def on_tool_result(&)
      set_legacy_callback(:tool_result, :on_tool_result, :after_tool_result, &)
    end

    def before_message(&)
      add_callback(:before_message, &)
    end

    def after_message(&)
      add_callback(:after_message, &)

# frozen_string_literal: true

module RubyLLM
  module Protocols
    class ChatCompletions
      # Handles formatting of media content (images, audio) for OpenAI APIs
      module Media
        module_function

        def format_content(content, document_attachments: :pdf, image_attachments: true, audio_attachments: true)
          format_parts(content) do |attachment|
            format_attachment(
              attachment,
              document_attachments:,
              image_attachments:,
              audio_attachments:
            )
          end
        end

        # Shared preamble and attachment loop for OpenAI-compatible providers.
        # The block formats a single attachment in the provider's dialect.
        def format_parts(content)
          if content.is_a?(RubyLLM::Content::Raw)
            value = content.value
            return value.is_a?(Hash) ? value.to_json : value
          end
          return content.to_json if content.is_a?(Hash) || content.is_a?(Array)
          return content unless content.is_a?(Content)

          parts = []
          parts << format_text(content.text) if content.text

          content.attachments.each do |attachment|
            parts << yield(attachment)
          end

          parts
        end

        def format_attachment(attachment, document_attachments:, image_attachments:, audio_attachments:)
          case attachment.type
          when :image
            raise UnsupportedAttachmentError, attachment.mime_type unless image_attachments

            format_image(attachment)
          when :audio
            raise UnsupportedAttachmentError, attachment.mime_type unless audio_attachments

            format_audio(attachment)
          when :pdf, :document
            format_document_attachment(attachment, document_attachments)
          when :text
            format_text_file(attachment)
          else
            raise UnsupportedAttachmentError, attachment.mime_type
          end
        end

        def format_image(image)
          {
            type: 'image_url',
            image_url: {
              url: image.url? ? image.source.to_s : image.for_llm
            }
          }
        end

        def format_document(document)
          {
            type: 'file',
            file: {
              filename: document.filename,
              file_data: document.for_llm
            }
          }
        end

        def format_text_file(text_file)
          {
            type: 'text',
            text: text_file.for_llm
          }
        end

        def format_audio(audio)
          {
            type: 'input_audio',
            input_audio: {
              data: audio.encoded,
              format: audio.format
            }
          }
        end

        def format_text(text)
          {
            type: 'text',
            text: text
          }
        end

        def format_document_attachment(attachment, strategy)
          return format_document(attachment) if strategy == :all
          return format_document(attachment) if strategy == :pdf && attachment.pdf?

          raise UnsupportedAttachmentError, attachment.mime_type
        end
      end
    end
  end
end
